import React, { useState, useEffect } from 'react';
import { useParams, useNavigate } from 'react-router-dom';
import { toast } from 'react-hot-toast';
import BookingForm from '../components/BookingForm';
import { MapPin, Wifi } from 'lucide-react';
import { propertyAPI, bookingAPI } from '../services/api';
import { useAuth } from '../contexts/AuthContext';

const PropertyDetails = () => {
    const { id } = useParams();
    const navigate = useNavigate();
    const { user } = useAuth();
    const [property, setProperty] = useState(null);
    const [loading, setLoading] = useState(true);

    useEffect(() => {
        // Fetch property details
        const fetchProperty = async () => {
            try {
                const data = await propertyAPI.getById(id);
                setProperty(data);
            } catch (error) {
                console.error('Error fetching property:', error);
                toast.error('Failed to load property details');
            } finally {
                setLoading(false);
            }
        };

        fetchProperty();
    }, [id]);

    const handleBooking = async (bookingData) => {
        if (!user) {
            toast.error('Please login to book a property');
            navigate('/login', { state: { from: `/properties/${id}` } });
            return;
        }

        try {
            await bookingAPI.create({
                propertyId: id,
                checkInDate: bookingData.checkIn,
                checkOutDate: bookingData.checkOut,
                guests: bookingData.guests
            });
            toast.success('Booking confirmed successfully!');
            navigate('/bookings');
        } catch (error) {
            console.error('Booking error:', error);
            toast.error(error.response?.data?.error || 'Failed to create booking');
        }
    };

    if (loading) return <div className="text-center py-10">Loading...</div>;
    if (!property) return <div className="text-center py-10">Property not found</div>;

    return (
        <div className="max-w-7xl mx-auto px-4 sm:px-6 lg:px-8 py-8">
            {/* Title and Location */}
            <div className="mb-6">
                <h1 className="text-3xl font-bold text-gray-900 mb-2">{property.title}</h1>
                <div className="flex items-center gap-2 text-gray-600">
                    <MapPin className="w-5 h-5" />
                    <span>{property.location}</span>
                </div>
            </div>

            {/* Image Gallery (Simplified) */}
            <div className="rounded-2xl overflow-hidden aspect-[2/1] mb-8 relative">
                <img
                    src={property.images?.[0] || 'https://via.placeholder.com/1200x600?text=No+Image'}
                    alt={property.title}
                    className="w-full h-full object-cover"
                />
            </div>

            <div className="grid grid-cols-1 lg:grid-cols-3 gap-12">
                {/* Main Content */}
                <div className="lg:col-span-2 space-y-8">
                    {/* Description */}
                    <div>
                        <h2 className="text-2xl font-semibold mb-4">About this place</h2>
                        <p className="text-gray-600 leading-relaxed">{property.description}</p>
                    </div>

                    {/* Amenities */}
                    <div className="border-t border-gray-200 pt-8">
                        <h2 className="text-2xl font-semibold mb-4">What this place offers</h2>
                        <div className="grid grid-cols-2 gap-4">
                            {property.amenities?.map((amenity, index) => (
                                <div key={index} className="flex items-center gap-3 text-gray-600">
                                    {/* You might want to map specific icons based on amenity name */}
                                    <Wifi className="w-6 h-6" />
                                    <span>{amenity}</span>
                                </div>
                            ))}
                            {(!property.amenities || property.amenities.length === 0) && (
                                <p className="text-gray-500">No specific amenities listed.</p>
                            )}
                        </div>
                    </div>
                </div>

                {/* Booking Sidebar */}
                <div>
                    <BookingForm property={property} onBook={handleBooking} />
                </div>
            </div>
        </div>
    );
};

export default PropertyDetails;
